import React from "react";
import { useUploader } from "../MainUploader";
import { Box, Button, Flex, Image, Text } from "../../../_compat";
import { Icon } from "../../../primitives";
import { useLanguage } from "../../../_compat";

const MultipleImageUploader = () => {
    const { onPick, files, removeFile, disabled, limit, isClassicUploader } =
        useUploader();
    const { t } = useLanguage();

    if (!isClassicUploader) {
        // Non-classic: dashed container with upload icon + localized phrase
        return (
            <Flex w={"full"} flexDirection={"column"} gap={8} opacity={disabled ? 0.5 : 1}>
                <Flex
                    w={"full"}
                    borderW={2}
                    borderStyle={"dashed"}
                    borderColor={"primary"}
                    borderRadiusLeft={"lg"}
                    borderRadiusRight={"lg"}
                    alignItems={"center"}
                    justifyContent={"center"}
                    flexDirection={"column"}
                    py={32}
                    px={16}
                    gap={8}
                    onClick={onPick as any}
                >
                    <Icon name="cloud-upload" size={'lg'} color={"primary"} />
                    <Text fontSize={14} color={"text-secondary"} textAlign={"center"}>
                        {t("tapToUpload")}
                    </Text>
                </Flex>
                {files.length > 0 && (
                    <Text fontSize={13} color={"text-secondary"} textAlign={"center"}>
                        {t("filesSelected", files.length)} / {limit}
                    </Text>
                )}
            </Flex>
        );
    }

    return (
        <Flex w={"full"} flexDirection={"column"} gap={8}>
            {files.map((f, idx) => {
                const uri =
                    typeof f.file === "object" && "uri" in f.file ? f.file.uri : null;

                return (
                    <Flex
                        key={`${f.name}-${idx}`}
                        flexDirection={"row"}
                        justifyContent={"space-between"}
                        alignItems={"center"}
                        gap={8}
                    >
                        <Flex flexDirection={"row"} alignItems={"center"} gap={8} flex={1}>
                            {uri ? (
                                <Image
                                    src={uri}
                                    alt={f.name}
                                    w={48}
                                    h={48}
                                    objectFit={"cover"}
                                    borderRadiusLeft={"md"}
                                    borderRadiusRight={"md"}
                                />
                            ) : null}
                            <Text
                                as={"span"}
                                fontSize={13}
                                color={"text-secondary"}
                                textOverflow={"ellipsis"}
                                whiteSpace={"nowrap"}
                            >
                                {f.shortName}
                            </Text>
                        </Flex>

                        <Button
                            icon="pi pi-times"
                            size={"sm"}
                            severity={"danger"}
                            onClick={removeFile(idx)}
                            disabled={disabled}
                        />
                    </Flex>
                );
            })}

            <Button
                label={t("addImages")}
                severity={"secondary"}
                outlined
                w={"full"}
                onClick={onPick as any}
                disabled={disabled || files.length >= limit}
            />
        </Flex>
    );
};

export default MultipleImageUploader;
